using Ledgerly.Domain.Common; using Ledgerly.Domain.Exceptions; namespace Ledgerly.Domain.Entities; public sealed class TaxCode:OrganizationScopedEntity{ public string Code{get;private set;}=string.Empty; public string Name{get;private set;}=string.Empty; public decimal Rate{get;private set;} public Guid LiabilityAccountId{get;private set;} private TaxCode(){} public TaxCode(Guid organizationId,string code,string name,decimal rate,Guid liabilityAccountId):base(organizationId){ if(string.IsNullOrWhiteSpace(code))throw new DomainException("Tax code is required."); if(liabilityAccountId==Guid.Empty)throw new DomainException("Tax liability account is required."); Code=code.Trim(); Name=name.Trim(); Rate=rate; LiabilityAccountId=liabilityAccountId; } }
